  glossary:[
    {term:"Feed Algorithm",def:"ML system ranking content in your feed by predicted engagement probability — analyzing: user behavior, content features, social signals, and context. Replaces chronological ordering. Unique per user."},
    {term:"Engagement",def:"User interactions with content: likes, comments, shares, saves, watch time, clicks. The primary metric algorithms optimize for. Higher engagement = more algorithmic distribution."},
    {term:"Embedding",def:"A mathematical vector (100-500 numbers) representing a user or content piece in a high-dimensional space. Similar users/content have similar embeddings — enabling recommendation through similarity search."},
    {term:"Collaborative Filtering",def:"Recommendation technique: 'users similar to you liked X → you might like X.' Based on finding patterns across millions of user-content interactions. The backbone of YouTube, Netflix, and social media recommendations."},
    {term:"Filter Bubble",def:"Algorithmic isolation where users primarily see content confirming their existing views/interests — reducing exposure to diverse perspectives. Created by engagement optimization, not political bias."},
    {term:"Engagement Rate",def:"The percentage of followers/viewers who interact with content. More important than follower count for algorithmic distribution. Typical: 1-5% for large accounts, 5-15% for smaller, engaged accounts."},
    {term:"A/B Testing",def:"Running simultaneous experiments on different user groups to measure the impact of algorithm changes. Platforms run thousands of concurrent A/B tests — each incrementally optimizing the algorithm."},
    {term:"Content Moderation",def:"AI + human review system detecting and removing: hate speech, violence, nudity, spam, misinformation, and copyright violations. Processes billions of content pieces. 95%+ automated, with human review for edge cases."},
    {term:"Shadowban",def:"Unofficial term for algorithmic deprioritization — content reaches fewer people without explicit notification. Triggered by: policy violations, spam behavior, banned hashtags, or third-party automation tools."},
    {term:"Creator Economy",def:"The ecosystem of individuals earning income through content creation. India: 80M+ creators, ₹1,300+ crore market. Revenue from: brand partnerships, ad revenue share, affiliate marketing, subscriptions, and merchandise."},
  ],
